from flask import Flask, jsonify, request
from datetime import datetime, timedelta

app = Flask(__name__)

# assuming database connection is already established
# and todo_list is a list of dictionaries
todo_list = []

# function to update progress
def update_progress():
    total_tasks = len(todo_list)
    completed_tasks = len([task for task in todo_list if task['completed']])
    progress = (completed_tasks / total_tasks) * 100 if total_tasks > 0 else 0
    return progress

# function to check due tasks
def check_due_tasks():
    due_tasks = [task for task in todo_list if task['due_date'] <= datetime.now()]
    return due_tasks

# function to check overdue tasks
def check_overdue_tasks():
    overdue_tasks = [task for task in todo_list if task['due_date'] < datetime.now()]
    return overdue_tasks

# API endpoint to get all tasks
@app.route('/tasks', methods=['GET'])
def get_tasks():
    return jsonify(todo_list)

# API endpoint to create a new task
@app.route('/tasks', methods=['POST'])
def create_task():
    new_task = {
        'id': len(todo_list) + 1,
        'title': request.json['title'],
        'description': request.json['description'],
        'due_date': datetime.strptime(request.json['due_date'], '%Y-%m-%d'),
        'completed': False
    }
    todo_list.append(new_task)
    return jsonify(new_task), 201

# API endpoint to update a task
@app.route('/tasks/<int:task_id>', methods=['PUT'])
def update_task(task_id):
    task = next((task for task in todo_list if task['id'] == task_id), None)
    if task is None:
        return jsonify({'message': 'Task not found'}), 404
    task['title'] = request.json.get('title', task['title'])
    task['description'] = request.json.get('description', task['description'])
    task['due_date'] = datetime.strptime(request.json.get('due_date', task['due_date'].strftime('%Y-%m-%d')), '%Y-%m-%d')
    task['completed'] = request.json.get('completed', task['completed'])
    return jsonify(task)

# API endpoint to delete a task
@app.route('/tasks/<int:task_id>', methods=['DELETE'])
def delete_task(task_id):
    task = next((task for task in todo_list if task['id'] == task_id), None)
    if task is None:
        return jsonify({'message': 'Task not found'}), 404
    todo_list.remove(task)
    return jsonify({'message': 'Task deleted'})

# API endpoint to get progress
@app.route('/progress', methods=['GET'])
def get_progress():
    progress = update_progress()
    return jsonify({'progress': progress})

# API endpoint to get due tasks
@app.route('/due-tasks', methods=['GET'])
def get_due_tasks():
    due_tasks = check_due_tasks()
    return jsonify(due_tasks)

# API endpoint to get overdue tasks
@app.route('/overdue-tasks', methods=['GET'])
def get_overdue_tasks():
    overdue_tasks = check_overdue_tasks()
    return jsonify(overdue_tasks)

# API endpoint to update whole list
@app.route('/tasks', methods=['PUT'])
def update_whole_list():
    global todo_list
    todo_list = request.json
    return jsonify(todo_list)

# API endpoint to delete whole list
@app.route('/tasks', methods=['DELETE'])
def delete_whole_list():
    global todo_list
    todo_list = []
    return jsonify({'message': 'Whole list deleted'})

if __name__ == '__main__':
    app.run(debug=True)

from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
from datetime import datetime, timedelta

app = Flask(__name__)
app.config["SQLALCHEMY_DATABASE_URI"] = "sqlite:///todo.db"
db = SQLAlchemy(app)

class TodoList(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    name = db.Column(db.String(100), nullable=False)
    items = db.relationship("TodoItem", backref="list", lazy=True)

class TodoItem(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    list_id = db.Column(db.Integer, db.ForeignKey("todo_list.id"), nullable=False)
    title = db.Column(db.String(100), nullable=False)
    description = db.Column(db.String(200), nullable=True)
    due_date = db.Column(db.DateTime, nullable=True)
    completed = db.Column(db.Boolean, default=False)

@app.route("/lists", methods=["GET", "POST"])
def handle_lists():
    if request.method == "GET":
        lists = TodoList.query.all()
        return jsonify([{"id": list.id, "name": list.name} for list in lists])
    elif request.method == "POST":
        data = request.get_json()
        new_list = TodoList(name=data["name"])
        db.session.add(new_list)
        db.session.commit()
        return jsonify({"id": new_list.id, "name": new_list.name}), 201

@app.route("/lists/<int:list_id>", methods=["GET", "PUT", "DELETE"])
def handle_list(list_id):
    list = TodoList.query.get_or_404(list_id)
    if request.method == "GET":
        return jsonify({"id": list.id, "name": list.name, "items": [{"id": item.id, "title": item.title, "description": item.description, "due_date": item.due_date, "completed": item.completed} for item in list.items]})
    elif request.method == "PUT":
        data = request.get_json()
        list.name = data["name"]
        db.session.commit()
        return jsonify({"id": list.id, "name": list.name})
    elif request.method == "DELETE":
        db.session.delete(list)
        db.session.commit()
        return jsonify({}), 204

@app.route("/lists/<int:list_id>/items", methods=["GET", "POST"])
def handle_items(list_id):
    list = TodoList.query.get_or_404(list_id)
    if request.method == "GET":
        return jsonify([{"id": item.id, "title": item.title, "description": item.description, "due_date": item.due_date, "completed": item.completed} for item in list.items])
    elif request.method == "POST":
        data = request.get_json()
        new_item = TodoItem(list_id=list_id, title=data["title"], description=data["description"], due_date=datetime.strptime(data["due_date"], "%Y-%m-%d"))
        db.session.add(new_item)
        db.session.commit()
        return jsonify({"id": new_item.id, "title": new_item.title, "description": new_item.description, "due_date": new_item.due_date, "completed": new_item.completed}), 201

@app.route("/lists/<int:list_id>/items/<int:item_id>", methods=["GET", "PUT", "DELETE"])
def handle_item(list_id, item_id):
    item = TodoItem.query.get_or_404(item_id)
    if request.method == "GET":
        return jsonify({"id": item.id, "title": item.title, "description": item.description, "due_date": item.due_date, "completed": item.completed})
    elif request.method == "PUT":
        data = request.get_json()
        item.title = data["title"]
        item.description = data["description"]
        item.due_date = datetime.strptime(data["due_date"], "%Y-%m-%d")
        item.completed = data["completed"]
        db.session.commit()
        return jsonify({"id": item.id, "title": item.title, "description": item.description, "due_date": item.due_date, "completed": item.completed})
    elif request.method == "DELETE":
        db.session.delete(item)
        db.session.commit()
        return jsonify({}), 204

@app.route("/progress", methods=["GET"])
def get_progress():
    lists = TodoList.query.all()
    progress = []
    for list in lists:
        completed = sum(1 for item in list.items if item.completed)
        total = len(list.items)
        progress.append({"list_id": list.id, "name": list.name, "progress": f"{completed}/{total}"})
    return jsonify(progress)

@app.route("/reminders", methods=["GET"])
def get_reminders():
    items = TodoItem.query.all()
    reminders = []
    for item in items:
        if item.due_date and item.due_date <= datetime.now():
            reminders.append({"item_id": item.id, "title": item.title, "due_date": item.due_date})
    return jsonify(reminders)

if __name__ == "__main__":
    app.run(debug=True)

from flask import Flask, jsonify, request
from datetime import datetime

app = Flask(__name__)

# Assuming database connection is already established
# Replace with actual database connection and queries

todo_list = {}

@app.route('/todo_list', methods=['GET', 'POST'])
def handle_todo_list():
    if request.method == 'POST':
        new_list_name = request.json['list_name']
        todo_list[new_list_name] = []
        return jsonify({'message': f'Todo list {new_list_name} created successfully'}), 201
    elif request.method == 'GET':
        return jsonify(todo_list), 200

@app.route('/todo_list/<list_name>', methods=['GET', 'PUT', 'DELETE'])
def handle_todo_list_by_name(list_name):
    if list_name not in todo_list:
        return jsonify({'message': f'Todo list {list_name} not found'}), 404
    if request.method == 'GET':
        return jsonify(todo_list[list_name]), 200
    elif request.method == 'PUT':
        new_list_name = request.json['list_name']
        todo_list[new_list_name] = todo_list.pop(list_name)
        return jsonify({'message': f'Todo list {list_name} updated to {new_list_name}'}), 200
    elif request.method == 'DELETE':
        del todo_list[list_name]
        return jsonify({'message': f'Todo list {list_name} deleted successfully'}), 200

@app.route('/todo_list/<list_name>/items', methods=['GET', 'POST'])
def handle_todo_items(list_name):
    if list_name not in todo_list:
        return jsonify({'message': f'Todo list {list_name} not found'}), 404
    if request.method == 'POST':
        new_item = request.json['item']
        due_date = request.json['due_date']
        todo_list[list_name].append({'item': new_item, 'due_date': due_date, 'completed': False})
        return jsonify({'message': f'Item {new_item} added to todo list {list_name}'}), 201
    elif request.method == 'GET':
        return jsonify(todo_list[list_name]), 200

@app.route('/todo_list/<list_name>/items/<item_index>', methods=['GET', 'PUT', 'DELETE'])
def handle_todo_item(list_name, item_index):
    if list_name not in todo_list:
        return jsonify({'message': f'Todo list {list_name} not found'}), 404
    try:
        item_index = int(item_index)
        if item_index < 0 or item_index >= len(todo_list[list_name]):
            return jsonify({'message': f'Item {item_index} not found in todo list {list_name}'}), 404
    except ValueError:
        return jsonify({'message': f'Invalid item index {item_index}'}), 400
    if request.method == 'GET':
        return jsonify(todo_list[list_name][item_index]), 200
    elif request.method == 'PUT':
        updated_item = request.json['item']
        updated_due_date = request.json['due_date']
        completed = request.json['completed']
        todo_list[list_name][item_index] = {'item': updated_item, 'due_date': updated_due_date, 'completed': completed}
        return jsonify({'message': f'Item {item_index} in todo list {list_name} updated successfully'}), 200
    elif request.method == 'DELETE':
        del todo_list[list_name][item_index]
        return jsonify({'message': f'Item {item_index} in todo list {list_name} deleted successfully'}), 200

@app.route('/todo_list/<list_name>/progress', methods=['GET'])
def handle_progress(list_name):
    if list_name not in todo_list:
        return jsonify({'message': f'Todo list {list_name} not found'}), 404
    total_items = len(todo_list[list_name])
    completed_items = sum(1 for item in todo_list[list_name] if item['completed'])
    progress = (completed_items / total_items) * 100 if total_items > 0 else 0
    return jsonify({'progress': progress}), 200

@app.route('/todo_list/<list_name>/reminders', methods=['GET'])
def handle_reminders(list_name):
    if list_name not in todo_list:
        return jsonify({'message': f'Todo list {list_name} not found'}), 404
    reminders = []
    for item in todo_list[list_name]:
        due_date = datetime.strptime(item['due_date'], '%Y-%m-%d')
        today = datetime.today()
        if due_date < today:
            reminders.append({'item': item['item'], 'due_date': item['due_date'], 'status': 'overdue'})
        elif due_date == today:
            reminders.append({'item': item['item'], 'due_date': item['due_date'], 'status': 'due today'})
    return jsonify(reminders), 200

if __name__ == '__main__':
    app.run(debug=True)

