def handle_lists():
    if request.method == "GET":
        lists = TodoList.query.all()
        return jsonify([{"id": list.id, "name": list.name} for list in lists])
    elif request.method == "POST":
        data = request.get_json()
        new_list = TodoList(name=data["name"])
