        return jsonify({"id": list.id, "name": list.name, "items": [{"id": item.id, "name": item.name, "due_date": item.due_date, "completed": item.completed} for item in list.items]})
    elif request.method == "PUT":
        data = request.get_json()
        list.name = data["name"]
        db.session.commit()
        return jsonify({"id": list.id, "name": list.name})
