from flask import Flask, jsonify, request
from datetime import datetime, timedelta

app = Flask(__name__)

# Assuming database connection is already established
# and a session object is created
from your_database import session, Todo, User

# Authentication function
def authenticate_user(token):
    user = session.query(User).filter_by(token=token).first()
    return user

# Create a new todo item
@app.route('/todo', methods=['POST'])
def create_todo():
    data = request.json
    token = data.get('token')
    user = authenticate_user(token)
    if user:
        new_todo = Todo(title=data['title'], description=data['description'], due_date=data['due_date'], user_id=user.id)
        session.add(new_todo)
        session.commit()
        return jsonify({'message': 'Todo item created successfully'}), 201
    else:
        return jsonify({'message': 'Invalid token'}), 401

# Get all todo items for a user
@app.route('/todo', methods=['GET'])
def get_all_todos():
    token = request.args.get('token')
    user = authenticate_user(token)
    if user:
        todos = session.query(Todo).filter_by(user_id=user.id).all()
        return jsonify([{'id': todo.id, 'title': todo.title, 'description': todo.description, 'due_date': todo.due_date} for todo in todos])
    else:
        return jsonify({'message': 'Invalid token'}), 401

# Update a todo item
@app.route('/todo/<int:todo_id>', methods=['PUT'])
def update_todo(todo_id):
    token = request.args.get('token')
    user = authenticate_user(token)
    if user:
        todo = session.query(Todo).filter_by(id=todo_id, user_id=user.id).first()
        if todo:
            data = request.json
            todo.title = data.get('title', todo.title)
            todo.description = data.get('description', todo.description)
            todo.due_date = data.get('due_date', todo.due_date)
            session.commit()
            return jsonify({'message': 'Todo item updated successfully'})
        else:
            return jsonify({'message': 'Todo item not found'}), 404
    else:
        return jsonify({'message': 'Invalid token'}), 401

# Delete a todo item
@app.route('/todo/<int:todo_id>', methods=['DELETE'])
def delete_todo(todo_id):
    token = request.args.get('token')
    user = authenticate_user(token)
    if user:
        todo = session.query(Todo).filter_by(id=todo_id, user_id=user.id).first()
        if todo:
            session.delete(todo)
            session.commit()
            return jsonify({'message': 'Todo item deleted successfully'})
        else:
            return jsonify({'message': 'Todo item not found'}), 404
    else:
        return jsonify({'message': 'Invalid token'}), 401

# Get progress of a user
@app.route('/progress', methods=['GET'])
def get_progress():
    token = request.args.get('token')
    user = authenticate_user(token)
    if user:
        todos = session.query(Todo).filter_by(user_id=user.id).all()
        total_todos = len(todos)
        completed_todos = len([todo for todo in todos if todo.completed])
        progress = (completed_todos / total_todos) * 100 if total_todos > 0 else 0
        return jsonify({'progress': progress})
    else:
        return jsonify({'message': 'Invalid token'}), 401

# Get reminders of overdue tasks
@app.route('/reminders', methods=['GET'])
def get_reminders():
    token = request.args.get('token')
    user = authenticate_user(token)
    if user:
        todos = session.query(Todo).filter_by(user_id=user.id).all()
        reminders = [todo for todo in todos if todo.due_date < datetime.now() and not todo.completed]
        return jsonify([{'id': todo.id, 'title': todo.title, 'description': todo.description, 'due_date': todo.due_date} for todo in reminders])
    else:
        return jsonify({'message': 'Invalid token'}), 401

if __name__ == '__main__':
    app.run(debug=True)

